#include <iostream>
#include <string>
#include <unistd.h>
#include <sys/wait.h>
#include <cstdio>

void playWithProcess() {
    int pipefd[2];  // Create a pipe
    if (pipe(pipefd) == -1) {
        perror("Pipe failed");
        return;
    }

    pid_t pid = fork();  // Fork a new process

    if (pid < 0) {  // Fork failed
        perror("Fork failed");
        return;
    } else if (pid > 0) {  // Parent process
        close(pipefd[0]);  // Close reading end in parent
        std::string message = "Hello from the parent!";
        write(pipefd[1], message.c_str(), message.size() + 1);  // Write to pipe
        close(pipefd[1]);  // Close writing end in parent
        wait(NULL);  // Wait for child to finish
    } else {  // Child process
        close(pipefd[1]);  // Close writing end in child
        dup2(pipefd[0], STDIN_FILENO);  // Redirect child's stdin to the pipe
        close(pipefd[0]);  // Close reading end in child
        execlp("/bin/cat", "cat", (char*)NULL);  // Run cat to read from pipe
        perror("execlp failed");
        return;
    }
}

int main() {
    playWithProcess();
    return 0;
}
```

